:root {
  /* Sarah Ghanem Training Center Brand Palette */
  --chat--color-primary: #1a5490;            /* Deep professional blue */
  --chat--color-primary-shade-50: #144374;   /* Hover/darker */
  --chat--color-primary-shade-100: #0f3258;  /* Active/darkest */
  --chat--color-secondary: #2c6aa0;          /* Lighter accent blue */
  --chat--color-secondary-shade-50: #3d7fb8; /* Light accent */
  --chat--color-accent: #f59e0b;             /* Warm gold accent */
  --chat--color-white: #ffffff;
  --chat--color-light: #f8fafc;              /* Light panel bg */
  --chat--color-light-shade-50: #e8f4f8;     /* Borders - light blue tint */
  --chat--color-light-shade-100: #d1e7f0;    /* Muted borders */
  --chat--color-medium: #cbd5e1;
  --chat--color-dark: #1f2937;               /* Primary text */
  --chat--color-disabled: #e5e7eb;
  --chat--color-typing: #6b7280;             /* Muted text */

  /* Base Layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.75rem;            /* 12px - professional rounded */
  --chat--transition-duration: 0.2s;
  --chat--font-family: 'Inter', system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;

  /* Window */
  --chat--window--width: 420px;
  --chat--window--height: 650px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid var(--chat--color-light-shade-50);
  --chat--window--border-radius: var(--chat--border-radius);
  --chat--window--margin-bottom: var(--chat--spacing);
  --chat--window--box-shadow: 0 10px 30px rgba(26, 84, 144, 0.15);

  /* Header - Brand Identity */
  --chat--header-height: auto;
  --chat--header--padding: 1.25rem var(--chat--spacing);
  --chat--header--background: linear-gradient(135deg, #1a5490 0%, #2c6aa0 100%);
  --chat--header--color: var(--chat--color-white);
  --chat--header--border-top: none;
  --chat--header--border-bottom: 2px solid var(--chat--color-accent);
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 1.25rem;       /* 20px - prominent */
  --chat--heading--font-weight: 600;
  --chat--subtitle--font-size: 0.875rem;
  --chat--subtitle--line-height: 1.6;
  --chat--subtitle--opacity: 0.9;

  /* Messages */
  --chat--message--font-size: 0.95rem;
  --chat--message--padding: 1rem;
  --chat--message--border-radius: 0.875rem;
  --chat--message-line-height: 1.6;
  --chat--message--margin-bottom: 1rem;

  /* Bot Messages - Clean white cards */
  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--bot--border: 1px solid var(--chat--color-light-shade-50);
  --chat--message--bot--box-shadow: 0 2px 8px rgba(26, 84, 144, 0.08);

  /* User Messages - Brand blue */
  --chat--message--user--background: var(--chat--color-primary);
  --chat--message--user--color: var(--chat--color-white);
  --chat--message--user--border: none;
  --chat--message--user--box-shadow: 0 2px 8px rgba(26, 84, 144, 0.2);

  /* Code blocks */
  --chat--message--pre--background: #f3f4f6;
  --chat--message--pre--border: 1px solid var(--chat--color-light-shade-100);
  --chat--messages-list--padding: var(--chat--spacing);

  /* Toggle FAB - Brand blue with accent */
  --chat--toggle--size: 60px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: var(--chat--color-primary);
  --chat--toggle--hover--background: var(--chat--color-primary-shade-50);
  --chat--toggle--active--background: var(--chat--color-primary-shade-100);
  --chat--toggle--color: var(--chat--color-white);
  --chat--toggle--box-shadow: 0 4px 12px rgba(26, 84, 144, 0.3);
  --chat--toggle--hover--box-shadow: 0 6px 16px rgba(26, 84, 144, 0.4);

  /* Input Area */
  --chat--textarea--height: 56px;
  --chat--textarea--max-height: 30rem;
  --chat--input--font-size: 0.95rem;
  --chat--input--border: 1px solid var(--chat--color-light-shade-50);
  --chat--input--border-radius: calc(var(--chat--border-radius) - 0.25rem);
  --chat--input--padding: 1rem;
  --chat--input--background: var(--chat--color-white);
  --chat--input--text-color: var(--chat--color-dark);
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: var(--chat--input--font-size);
  --chat--input--placeholder--color: var(--chat--color-typing);
  --chat--input--border-active: 2px solid var(--chat--color-primary);
  --chat--input--left--panel--width: 2.5rem;

  /* Buttons */
  --chat--button--color: var(--chat--color-white);
  --chat--button--background: var(--chat--color-primary);
  --chat--button--padding: 0.65rem 1.25rem;
  --chat--button--border-radius: 0.625rem;
  --chat--button--font-weight: 500;
  --chat--button--hover--color: var(--chat--color-white);
  --chat--button--hover--background: var(--chat--color-primary-shade-50);
  --chat--button--box-shadow: 0 2px 6px rgba(26, 84, 144, 0.2);
  --chat--close--button--color-hover: var(--chat--color-primary);

  /* Send Button - Primary brand */
  --chat--input--send--button--background: var(--chat--color-primary);
  --chat--input--send--button--color: var(--chat--color-white);
  --chat--input--send--button--background-hover: var(--chat--color-primary-shade-50);
  --chat--input--send--button--color-hover: var(--chat--color-white);
  --chat--input--send--button--border-radius: 0.5rem;

  /* File Button */
  --chat--input--file--button--background: var(--chat--color-light);
  --chat--input--file--button--color: var(--chat--color-primary);
  --chat--input--file--button--background-hover: var(--chat--color-light-shade-50);
  --chat--input--file--button--color-hover: var(--chat--color-primary-shade-50);

  --chat--files-spacing: 0.5rem;

  /* Surfaces */
  --chat--body--background: #fafbfc;
  --chat--footer--background: var(--chat--color-white);
  --chat--footer--color: var(--chat--color-dark);
  --chat--footer--border-top: 1px solid var(--chat--color-light-shade-50);
  --chat--footer--padding: 1rem;

  /* Typing Indicator */
  --chat--typing--color: var(--chat--color-primary);

  /* Scrollbar */
  --chat--scrollbar--width: 6px;
  --chat--scrollbar--track: var(--chat--color-light);
  --chat--scrollbar--thumb: var(--chat--color-medium);
  --chat--scrollbar--thumb-hover: var(--chat--color-primary);
}

/* Additional brand-specific enhancements */
.chat-header-title {
  font-weight: 600;
  letter-spacing: -0.01em;
}

.chat-header-subtitle {
  opacity: 0.9;
  font-weight: 400;
}

.chat-message-bot {
  animation: fadeInUp 0.3s ease-out;
}

.chat-message-user {
  animation: fadeInRight 0.3s ease-out;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInRight {
  from {
    opacity: 0;
    transform: translateX(10px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

/* Branding watermark (optional) */
.chat-footer::after {
  content: "Powered by Sarah Ghanem Training Center";
  display: block;
  text-align: center;
  font-size: 0.75rem;
  color: var(--chat--color-typing);
  margin-top: 0.5rem;
  opacity: 0.7;
}

