const item = (items[0] && items[0].json) || {};

// Get parameters
const participants = Number(item.participants || 0);
const days = Number(item.days || 0);
const format = String(item.delivery_format || "").trim().toLowerCase();

// Validation
if (!Number.isFinite(participants)) throw new Error("participants must be a number");
if (!Number.isFinite(days)) throw new Error("days must be a number");
if (participants <= 0) throw new Error("participants must be greater than 0");
if (days <= 0) throw new Error("days must be greater than 0");

// Pricing tiers
const tiers = {
  small: { price: 450, min: 1, max: 10 },
  medium: { price: 400, min: 11, max: 20 },
  large: { price: 350, min: 21, max: 30 },
  xlarge: { price: 320, min: 31, max: 50 },
  xxlarge: { price: 280, min: 51, max: 999 }
};

// Find tier
let tier = null;
let tierName = "";
for (const [name, t] of Object.entries(tiers)) {
  if (participants >= t.min && participants <= t.max) {
    tier = t;
    tierName = name;
    break;
  }
}

if (!tier) throw new Error("Unable to determine pricing tier");

// Delivery format multiplier
const formats = {
  virtual: 1.0,
  onsite: 1.2,
  "on-site": 1.2,
  hybrid: 1.1
};

const multiplier = formats[format] || 1.0;

// Calculate
const basePrice = participants * tier.price * days;
const total = basePrice * multiplier;
const deposit = total * 0.5;

// Generate quote ID
const quoteId = `QT-2026-${Math.floor(Math.random() * 900) + 100}`;

// Return
return JSON.stringify([{
  json: {
    quote_id: quoteId,
    participants: participants,
    days: days,
    delivery_format: format || "virtual",
    tier: tierName,
    price_per_person_per_day: tier.price,
    base_price: Math.round(basePrice),
    delivery_multiplier: multiplier,
    total: Math.round(total),
    deposit_50_percent: Math.round(deposit),
    final_payment_50_percent: Math.round(deposit),
    currency: "USD"
  }
}]);

